import { GoogleGenAI, Type } from "@google/genai";
import { FoodItem } from "../types";

const apiKey = process.env.API_KEY || '';

// Initialize the client. 
// Note: In a real production app, you might proxy this through a backend 
// to keep the key secure, but for this demo, we use the env var directly.
const ai = new GoogleGenAI({ apiKey });

/**
 * Analyzes an image of food to extract a list of items and estimated expiration.
 */
export const analyzeFoodImage = async (base64Image: string): Promise<{ items: FoodItem[], description: string }> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image', // Good for image analysis
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Image,
              mimeType: 'image/jpeg',
            },
          },
          {
            text: `Analyze this image of food. 
            1. Identify the food items present.
            2. Estimate the quantity of each.
            3. Provide a brief, appealing description of the donation.
            Return JSON.`
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            items: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  quantity: { type: Type.STRING },
                  expiryEstimate: { type: Type.STRING, description: "e.g., '2 days', '1 week'" }
                }
              }
            },
            description: { type: Type.STRING }
          }
        }
      }
    });

    const text = response.text;
    if (!text) return { items: [], description: "Could not analyze image." };

    return JSON.parse(text);

  } catch (error) {
    console.error("Gemini analysis failed:", error);
    return { 
      items: [{ name: "Unknown Item", quantity: "1", expiryEstimate: "Unknown" }], 
      description: "Auto-analysis failed. Please describe manually." 
    };
  }
};

/**
 * Generates the Supabase SQL Schema based on user requirements.
 * Used for the 'Developer Mode' view in the app.
 */
export const generateSQLSchema = async (): Promise<string> => {
    // We are hardcoding the prompt's request here to ensure the AI generates exactly what was asked
    // This allows the app to be "smart" about its own backend structure.
    const prompt = `
    Write a PostgreSQL SQL schema for a Supabase project called 'FoodConnect'.

    Tables required:
    1. profiles: Users (id uuid PK, role text [donor/volunteer], name text, avatar_url text, verified_status boolean).
    2. donations: (id uuid PK, donor_id uuid FK profiles.id, food_items jsonb, pickup_window_start timestamptz, pickup_window_end timestamptz, status text [active/claimed/completed], location_lat float, location_long float).
    3. claims: (id uuid PK, donation_id uuid FK donations.id, volunteer_id uuid FK profiles.id, claim_time timestamptz, proof_photo_url text).

    Add Row Level Security (RLS) policies:
    - Donors can insert and update their own donations.
    - Volunteers can view all active donations.
    - Profiles are publicly readable.

    Output strictly SQL code.
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
        });
        return response.text || "-- Error generating SQL";
    } catch (e) {
        return "-- Error connecting to Gemini for SQL generation";
    }
}

import React, { useEffect, useState } from 'react';
