                                onChange={(e) => setQuantity(parseInt(e.target.value) || 0)}
                                className="text-3xl font-bold text-stone-900 bg-transparent text-center w-24 focus:outline-none p-0"
                            />
                        </div>
                        <span className="text-xs text-stone-500 font-medium uppercase tracking-wide">Kilograms</span>
                    </div>
                    <button 
                        type="button" 
                        onClick={() => adjustQuantity(1)}
                        className="w-10 h-10 rounded-lg bg-white border border-stone-200 flex items-center justify-center text-stone-600 hover:bg-stone-100 hover:border-stone-300 transition-all active:scale-95 shadow-sm"
                    >
                        <Plus size={20} />
                    </button>
                </div>
                <input 
                    type="range" 
                    min="1" 
                    max="50" 
                    value={quantity} 
                    onChange={(e) => setQuantity(parseInt(e.target.value))}
                    className="w-full accent-forest-600 h-2 bg-stone-200 rounded-lg appearance-none cursor-pointer"
                />
                <div className="flex justify-between text-xs text-stone-400 mt-2 font-medium">
                    <span>1 kg</span>
                    <span>25 kg</span>
                    <span>50+ kg</span>
                </div>
            </div>
        </div>

        {/* Time Window Redesign */}
        <div>
            <label className="block text-sm font-medium text-stone-700 mb-3">Pickup Availability</label>
            <div className="bg-stone-50 rounded-xl p-4 border border-stone-200 space-y-4">
                {/* Quick Chips */}
                <div>
                     <p className="text-xs text-stone-400 font-medium mb-2 uppercase tracking-wide">Quick Select</p>
                     <div className="flex gap-2 overflow-x-auto pb-1 no-scrollbar">
                        <button type="button" onClick={() => setQuickTime('1h')} className="px-3 py-1.5 bg-white border border-stone-200 rounded-md text-xs font-medium text-stone-600 hover:bg-forest-50 hover:border-forest-200 hover:text-forest-700 transition-colors whitespace-nowrap shadow-sm">
                            +1 Hour
                        </button>
                         <button type="button" onClick={() => setQuickTime('2h')} className="px-3 py-1.5 bg-white border border-stone-200 rounded-md text-xs font-medium text-stone-600 hover:bg-forest-50 hover:border-forest-200 hover:text-forest-700 transition-colors whitespace-nowrap shadow-sm">
                            +2 Hours
                        </button>
                        <button type="button" onClick={() => setQuickTime('4h')} className="px-3 py-1.5 bg-white border border-stone-200 rounded-md text-xs font-medium text-stone-600 hover:bg-forest-50 hover:border-forest-200 hover:text-forest-700 transition-colors whitespace-nowrap shadow-sm">
                            +4 Hours
                        </button>
                         <button type="button" onClick={() => setQuickTime('eod')} className="px-3 py-1.5 bg-white border border-stone-200 rounded-md text-xs font-medium text-stone-600 hover:bg-forest-50 hover:border-forest-200 hover:text-forest-700 transition-colors whitespace-nowrap shadow-sm">
                            Until 10 PM
                        </button>
                    </div>
                </div>

                {/* Inputs */}
                <div className="flex items-center gap-3">
                     <div className="flex-1">
                        <label className="text-xs text-stone-500 font-semibold mb-1 block flex items-center gap-1"><Clock size={12}/> Start Time</label>
                        <input
                            type="time"
                            value={startTime}
                            onChange={(e) => setStartTime(e.target.value)}
                            className="w-full px-3 py-2 bg-white rounded-lg border border-stone-200 focus:outline-none focus:border-forest-500 text-sm font-medium text-stone-800"
                        />
                    </div>
                    <div className="pt-5 text-stone-400">
                        <ArrowRight size={16} />
                    </div>
                     <div className="flex-1">
                        <label className="text-xs text-stone-500 font-semibold mb-1 block flex items-center gap-1"><Clock size={12}/> End Time</label>
                        <input
                            type="time"
                            value={endTime}
                            onChange={(e) => setEndTime(e.target.value)}
                            className="w-full px-3 py-2 bg-white rounded-lg border border-stone-200 focus:outline-none focus:border-forest-500 text-sm font-medium text-stone-800"
                        />
                    </div>
                </div>
            </div>
        </div>

        <button
          type="submit"
          className="w-full bg-forest-700 text-white font-medium py-3 rounded-lg hover:bg-forest-800 transition-all shadow-sm flex items-center justify-center gap-2 active:scale-[0.99]"
        >
          {initialData ? 'Update Donation' : 'Broadcast Availability'}
          <ArrowRight size={18} />
        </button>

      </form>
    </div>
  );
};

export default Donate;
